mapper.select:
SELECT h.id, h.name, h.definition, h.example, h.tags, h.image_url as imageUrl, h.total_votes as totalVotes, h.status, h.is_recommended as isRecommended, h.user_id as userId, h.create_time as createTime, u.nickname as authorNickname, u.avatar as authorAvatar FROM hotword h LEFT JOIN sys_user u ON h.user_id = u.id
h.status = #{status}
ORDER BY h.total_votes DESC, h.create_time DESC

